class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, data):
        new_node = Node(data)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def print_list(self):
        current = self.head
        while current:
            print(current.data, end=" -> " if current.next else "")
            current = current.next
        print()

    def delete_n_after_m(self, M, N):
        if N <= 0:
            return

        if not self.head:
            return

        if M == 0:
            current = self.head
            for _ in range(N):
                if current is None:
                    break
                current = current.next
            self.head = current
            return

        current = self.head
        for _ in range(M - 1):
            if current is None:
                return
            current = current.next

        if current is None:
            return

        node_after_deletion_end = current.next
        for _ in range(N):
            if node_after_deletion_end is None:
                break
            node_after_deletion_end = node_after_deletion_end.next

        current.next = node_after_deletion_end
